mapper.select:
SELECT USR_SN
FROM USER_OAUTH
WHERE USR_OAT_PROVIDER_CD = #{providerCd}
  AND USR_OAT_PROVIDER_KEY = #{providerKey}

mapper.insert:
INSERT INTO USER_OAUTH (
    USR_SN, USR_OAT_PROVIDER_CD, USR_OAT_PROVIDER_KEY
) VALUES (
    #{usrSn}, #{providerCd}, #{providerKey}
)

mapper.select:
SELECT USR_OAT_PROVIDER_CD, USR_OAT_REG_DT
FROM USER_OAUTH
WHERE USR_SN = #{usrSn}

mapper.delete:
DELETE FROM USER_OAUTH
WHERE USR_SN = #{usrSn}
  AND USR_OAT_PROVIDER_CD = #{providerCd}
